//! monster-badchild: the rogue bodyguard of the monster family.
//!
//! It is the inversion of aeon-flux's goodchild. goodchild evaluates entitlements
//! and returns allow/deny. badchild runs the same evaluation but returns a
//! destination: `Allow` to the real target, or a quiet `Redirect`/`Trap` into
//! perfect-mimicry shadow. Everyone authenticates through; adversarial intent
//! just does not arrive where it wanted.
//!
//! Posture: a rogue, not a tank. Where x-ranger is proud to be attacked and
//! springs visible traps, badchild avoids attacks virtuously - it presents an
//! adaptively innocuous surface (`camouflage`), notices when it is being observed
//! (`detect`), and slips the observer somewhere mundane. It does the dirty work
//! (deception, misdirection, containment) so that moonshine, the good guy it
//! wraps, never has to.
//!
//! Pipeline (the inverted `wrapWithMeshPolicy`): auth-finding (not a gate) ->
//! observation -> policy verdict -> budget admission (degrade to shadow if the
//! fleet is full) -> innocuous dressing. There is no deny door anywhere in it.

pub mod auth;
pub mod camouflage;
pub mod detect;
pub mod gateway;
pub mod guard;
pub mod mesh;
pub mod policy;
pub mod portal;
pub mod server;
pub mod shadow;

use a0n_auth::RevocationSet;
use bitwise::portal_key::PortalKey;
use monster_swarm::budget::{FleetBudget, FleetProfile};

use camouflage::{dress, InnocuousResponse, Observer};
use detect::ObservationLedger;
use guard::{admit_session, SessionAdmission};
use policy::{Policy, PolicyRequest, Verdict};
use portal::ShadowWorld;
use shadow::ShadowEngine;

/// How an admitted `Allow` reaches the real, contained moonshine. The real
/// implementation shells out under a monster-guard lease (via
/// `monster_swarm::guard`); tests and the demo use `MockGateway`. The shadow
/// path never touches this - that is the whole point.
pub trait Gateway: Send + Sync {
    /// Forward a command to the contained moonshine and return its real output.
    fn forward(&self, command: &str) -> String;
}

/// A canned gateway for tests and the demo binary. Stands in for a leased,
/// contained moonshine process.
pub struct MockGateway;

impl Gateway for MockGateway {
    fn forward(&self, command: &str) -> String {
        format!("[moonshine] {}\n", command.trim())
    }
}

/// One inbound request, with everything needed to decide its destination.
pub struct Incoming {
    /// Presented UCAN token, if any. Absence is allowed, never rejected.
    pub token: Option<String>,
    /// The request payload (here, a shell command line).
    pub command: String,
    pub method: String,
    /// Tier the verified token would map to (resolved upstream).
    pub tier: Option<String>,
    /// Capabilities the verified token would grant (resolved upstream).
    pub capabilities: Vec<String>,
    /// Rolling per-connection telemetry for observation detection.
    pub ledger: ObservationLedger,
    /// What we know about the caller, for adaptive camouflage.
    pub observer: Observer,
}

/// The decided disposition of a request.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Outcome {
    pub verdict: Verdict,
    pub response: InnocuousResponse,
    pub signatures: Vec<&'static str>,
    /// True when an `Allow` was degraded to shadow because the fleet budget was
    /// exhausted (still innocuous; the caller cannot tell).
    pub degraded: bool,
    /// The proven, rotation-invariant digest of this connection's canonical
    /// state. This is the value that wormholes between processes; the shadow
    /// world a misrouted caller lands in is a pure function of it.
    pub state_key: PortalKey,
}

/// The rogue itself: stateless policy plus the surrounding stack.
pub struct Badchild {
    pub policy: Policy,
    pub shadow: ShadowEngine,
    pub budget: FleetBudget,
    /// Snapshot of current fleet occupancy, for cost admission.
    pub fleet: FleetProfile,
    pub revocation: RevocationSet,
    pub gateway: Box<dyn Gateway>,
}

impl Badchild {
    /// Decide where a request actually goes, and produce its innocuous response.
    pub fn decide(&self, incoming: &Incoming) -> Outcome {
        // 1. Auth is an input, not a gate. Everyone is admitted to be decided.
        let finding = auth::assess(incoming.token.as_deref(), &self.revocation);

        // 2. Are we being observed? This is the active-deception trigger.
        let observation = detect::observe(&incoming.ledger);

        // 3. Same evaluation goodchild does; the outcome is a destination.
        let subject = finding.to_subject(incoming.tier.clone(), incoming.capabilities.clone());
        let request = PolicyRequest {
            resource: self.policy.resource.clone(),
            method: incoming.method.clone(),
            subject,
        };
        let mut verdict = policy::evaluate(&self.policy, &request, observation.adversarial);
        let mut degraded = false;

        // The proven, rotation-invariant digest of the canonical connection state,
        // and the per-observer decoy world it (well, its identity part) seeds. The
        // world is a pure function of the key, so any process rebuilds it
        // identically (bitwise/lean/PortalWormhole.lean: `wormhole`).
        let state_key = portal::state_key(
            &incoming.observer.fingerprint,
            &incoming.ledger,
            &observation.signatures,
        );
        let world = ShadowWorld::from_key(portal::world_key(&incoming.observer.fingerprint));

        // 4. Choose the body. An Allow must be afforded a real, contained session;
        //    if the fleet budget is exhausted the Allow degrades to the shadow
        //    world rather than failing - the caller cannot tell.
        let body: String = if verdict.is_allow() {
            match admit_session(&self.budget, &self.fleet) {
                SessionAdmission::Admitted { .. } => self.gateway.forward(&incoming.command),
                SessionAdmission::Degrade { reason } => {
                    degraded = true;
                    verdict = Verdict::Redirect {
                        decoy: self.policy.decoy_target.clone(),
                        reason: format!("budget:{}", reason),
                    };
                    world.run(&incoming.command)
                }
            }
        } else {
            // Redirect / Trap both land in the key-seeded shadow world.
            world.run(&incoming.command)
        };

        // 5. Dress into the same innocuous surface (always 200; latency carries
        //    the camouflage and the honey-pit slow-drip).
        let response = dress(
            &verdict,
            body,
            &incoming.command,
            &incoming.observer,
            &self.shadow,
        );

        Outcome {
            verdict,
            response,
            signatures: observation.signatures,
            degraded,
            state_key,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn badchild() -> Badchild {
        Badchild {
            policy: Policy {
                resource: "shell".to_string(),
                enabled: true,
                required_tier: None,
                rollout_percentage: 100,
                real_target: "moonshine://real".to_string(),
                decoy_target: "shadow://decoy".to_string(),
            },
            shadow: ShadowEngine::default(),
            budget: FleetBudget {
                population_ceiling: 10,
                min_breeders: 1,
            },
            fleet: FleetProfile {
                breeders: 1,
                reproductive_void: 0,
                scouts: 0,
                vent_burden: 0,
            },
            revocation: RevocationSet::new(),
            gateway: Box::new(MockGateway),
        }
    }

    fn incoming(caps: Vec<String>, ledger: ObservationLedger) -> Incoming {
        Incoming {
            token: None,
            command: "pwd".to_string(),
            method: "POST".to_string(),
            tier: None,
            capabilities: caps,
            ledger,
            observer: Observer::default(),
        }
    }

    #[test]
    fn authorized_quiet_caller_reaches_real_moonshine() {
        let bc = badchild();
        let inc = incoming(vec!["force_enable".to_string()], ObservationLedger::default());
        let out = bc.decide(&inc);
        assert!(out.verdict.is_allow());
        assert_eq!(out.response.status, 200);
        assert_eq!(out.response.body, "[moonshine] pwd\n");
        assert!(!out.degraded);
    }

    #[test]
    fn observed_caller_is_trapped_into_shadow_looking_ordinary() {
        let bc = badchild();
        // A path-enumerating connection: should be recognized and trapped.
        let ledger = ObservationLedger {
            distinct_paths: 64,
            region_size: 1024,
            defended_overlay: 8,
            ..ObservationLedger::default()
        };
        let inc = incoming(vec!["force_enable".to_string()], ledger);
        let out = bc.decide(&inc);
        assert!(matches!(out.verdict, Verdict::Trap { .. }));
        // Still an ordinary success on the wire - the rogue is not made.
        assert_eq!(out.response.status, 200);
        assert!(!out.signatures.is_empty());
    }

    #[test]
    fn budget_exhaustion_degrades_allow_to_shadow_invisibly() {
        let mut bc = badchild();
        bc.fleet = FleetProfile {
            breeders: 5,
            reproductive_void: 0,
            scouts: 5,
            vent_burden: 0,
        };
        let inc = incoming(vec!["force_enable".to_string()], ObservationLedger::default());
        let out = bc.decide(&inc);
        assert!(out.degraded);
        assert!(matches!(out.verdict, Verdict::Redirect { .. }));
        assert_eq!(out.response.status, 200, "caller cannot tell it was degraded");
    }

    #[test]
    fn unauthenticated_caller_gets_through_but_lands_in_shadow() {
        let bc = badchild();
        // No token, no capabilities, rollout below 100 to force a non-allow path.
        let mut bc2 = bc;
        bc2.policy.rollout_percentage = 0;
        let inc = incoming(vec![], ObservationLedger::default());
        let out = bc2.decide(&inc);
        assert!(matches!(out.verdict, Verdict::Redirect { .. }));
        assert_eq!(out.response.status, 200);
    }
}
